import{_ as s,o as n,c as t,a1 as e}from"./chunks/framework.BKJzsOC1.js";const p="/assets/figure-9-entry-timing.IodSBRnU.png",b=JSON.parse('{"title":"第九章：③后的建仓时机与追价控制","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/09-entry-timing-and-chase-control.md","filePath":"trading/intraday-entry/09-entry-timing-and-chase-control.md"}'),l={name:"trading/intraday-entry/09-entry-timing-and-chase-control.md"};function i(d,a,o,c,h,r){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="第九章-3后的建仓时机与追价控制" tabindex="-1">第九章：③后的建仓时机与追价控制 <a class="header-anchor" href="#第九章-3后的建仓时机与追价控制" aria-label="Permalink to &quot;第九章：③后的建仓时机与追价控制&quot;">​</a></h1><blockquote><p>③是第一个可执行确认，但不是看到③就必须重仓追入。</p></blockquote><p>前面已经确认：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 突破关键位</span></span>
<span class="line"><span>② 回踩守住</span></span>
<span class="line"><span>③ 突破回踩结构</span></span></code></pre></div><p>本章进一步回答：③出现后，应该立即建仓、等待收盘，还是等待二次回踩？</p><h2 id="一、3出现后有四种状态" tabindex="-1">一、③出现后有四种状态 <a class="header-anchor" href="#一、3出现后有四种状态" aria-label="Permalink to &quot;一、③出现后有四种状态&quot;">​</a></h2><p><img src="`+p+`" alt="③出现后的四种建仓位置"></p><p><em>图 1：同一段上涨结构中，③刚出现、③收盘确认、③后的二次回踩，以及已经远离触发位的追价位置。图中价格为构造示例。</em></p><h3 id="_1-3刚出现-早-但证据较少" tabindex="-1">1. ③刚出现：早，但证据较少 <a class="header-anchor" href="#_1-3刚出现-早-但证据较少" aria-label="Permalink to &quot;1. ③刚出现：早，但证据较少&quot;">​</a></h3><p>价格刚突破回踩高点时，方向已经得到初步确认，但仍可能出现：</p><ul><li>影线假突破；</li><li>突破后立即回到旧区间；</li><li>上方供给区距离过近；</li><li>目标空间不足。</li></ul><p>如果使用这种方式，只能考虑小仓试探，并且必须提前定义结构止损。学习阶段不把它作为默认入场点。</p><h3 id="_2-3收盘确认-默认方式" tabindex="-1">2. ③收盘确认：默认方式 <a class="header-anchor" href="#_2-3收盘确认-默认方式" aria-label="Permalink to &quot;2. ③收盘确认：默认方式&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>③突破</span></span>
<span class="line"><span>→ 等待1分钟K收盘</span></span>
<span class="line"><span>→ 实体仍在触发位外侧</span></span>
<span class="line"><span>→ 检查目标空间与结构止损</span></span>
<span class="line"><span>→ 建仓</span></span></code></pre></div><p>收盘确认可以过滤许多“盘中刺穿、收盘跌回”的假突破。代价是入场价格可能更高，甚至可能错过行情，但这是用成交价格换取结构证据。</p><h3 id="_3-3后的二次回踩-更保守" tabindex="-1">3. ③后的二次回踩：更保守 <a class="header-anchor" href="#_3-3后的二次回踩-更保守" aria-label="Permalink to &quot;3. ③后的二次回踩：更保守&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>③突破并收盘</span></span>
<span class="line"><span>→ 小幅回踩触发位或③附近</span></span>
<span class="line"><span>→ 回踩没有重新跌回旧区间</span></span>
<span class="line"><span>→ 再建立主要仓位</span></span></code></pre></div><p>这种方式的价格可能不如第一次突破便宜，但通常拥有更清楚的失效点，适合学习阶段和波动较大的 0DTE 环境。</p><h3 id="_4-已经远离3-不追价" tabindex="-1">4. 已经远离③：不追价 <a class="header-anchor" href="#_4-已经远离3-不追价" aria-label="Permalink to &quot;4. 已经远离③：不追价&quot;">​</a></h3><p>如果价格已经：</p><ul><li>接近上方供给区或第一目标；</li><li>明显远离 VWAP 和触发位；</li><li>结构止损距离变大；</li><li>剩余收益不足以覆盖风险；</li></ul><p>即使方向判断正确，也不应再追入。等待新的高低点结构或下一次回踩。</p><h2 id="二、如何选择入场方式" tabindex="-1">二、如何选择入场方式 <a class="header-anchor" href="#二、如何选择入场方式" aria-label="Permalink to &quot;二、如何选择入场方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>证据</th><th>风险</th><th>学习阶段处理</th></tr></thead><tbody><tr><td>③刚出现</td><td>初步确认</td><td>假突破风险较高</td><td>小仓或等待</td></tr><tr><td>③收盘确认</td><td>结构和收线同时支持</td><td>价格略差</td><td>默认方式</td></tr><tr><td>二次回踩</td><td>两次测试均守住</td><td>可能错过</td><td>保守优先</td></tr><tr><td>远离触发位</td><td>方向可能仍对</td><td>盈亏比变差</td><td>放弃追价</td></tr></tbody></table><p>默认优先级：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>③收盘确认 + 二次回踩</span></span>
<span class="line"><span>&gt; ③收盘确认</span></span>
<span class="line"><span>&gt; ③刚出现小仓试探</span></span>
<span class="line"><span>&gt; 远离③后追价</span></span></code></pre></div><h2 id="三、用盈亏比决定是否值得建仓" tabindex="-1">三、用盈亏比决定是否值得建仓 <a class="header-anchor" href="#三、用盈亏比决定是否值得建仓" aria-label="Permalink to &quot;三、用盈亏比决定是否值得建仓&quot;">​</a></h2><p>③出现并不等于这笔交易值得做。还要计算：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>风险 = 入场价格 − 结构止损</span></span>
<span class="line"><span>潜在收益 = 第一目标 − 入场价格</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键位：7500</span></span>
<span class="line"><span>③突破：7504</span></span>
<span class="line"><span>二次回踩：7502—7503，仍然守住</span></span>
<span class="line"><span>结构止损：7500下方</span></span>
<span class="line"><span>第一目标：7515附近</span></span></code></pre></div><p>如果价格在二次回踩后仍有足够目标空间，可以继续评估；如果已经冲到 <code>7513</code> 附近，再追入时剩余收益很小，即使方向正确，也可能不值得承担结构风险。</p><p>不要把“至少多少点”当成固定规则，因为 SPX 的波动会随时段和环境变化。应该根据当前结构止损距离和下一个供给/阻力位置计算。</p><h2 id="四、5分钟与1分钟怎样配合" tabindex="-1">四、5分钟与1分钟怎样配合 <a class="header-anchor" href="#四、5分钟与1分钟怎样配合" aria-label="Permalink to &quot;四、5分钟与1分钟怎样配合&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟：确认环境和关键位</span></span>
<span class="line"><span>1分钟：确认③、收盘和二次回踩</span></span></code></pre></div><p>如果 1 分钟已经出现③，但 5 分钟仍然：</p><ul><li>处于明显下降结构；</li><li>位于 VWAP 下方；</li><li>接近供给区；</li><li>距离下一目标太近；</li></ul><p>则信号应降级。不能让一根 1 分钟漂亮 K 线推翻整个 5 分钟环境。</p><h2 id="五、入场后的时间确认" tabindex="-1">五、入场后的时间确认 <a class="header-anchor" href="#五、入场后的时间确认" aria-label="Permalink to &quot;五、入场后的时间确认&quot;">​</a></h2><p>建仓后，如果连续 2—4 根 1 分钟 K 线仍然无法离开触发位，说明市场没有按照预期产生位移。</p><p>此时可以：</p><ul><li>减仓；</li><li>把观察仓退出；</li><li>或在价格重新收回旧区间时直接退出。</li></ul><p>时间止损不是因为“持仓时间到了”就机械卖出，而是因为价格在应该推进的地方没有推进。</p><h2 id="六、本章执行卡" tabindex="-1">六、本章执行卡 <a class="header-anchor" href="#六、本章执行卡" aria-label="Permalink to &quot;六、本章执行卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>③是否已经出现：</span></span>
<span class="line"><span>③是否收盘确认：</span></span>
<span class="line"><span>是否等待二次回踩：</span></span>
<span class="line"><span>入场价格：</span></span>
<span class="line"><span>结构止损：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>剩余空间是否足够：</span></span>
<span class="line"><span>5分钟环境是否支持：</span></span>
<span class="line"><span>入场后2—4根1分钟K是否产生位移：</span></span></code></pre></div><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>③刚出现：方向初步确认</span></span>
<span class="line"><span>③收盘确认：过滤假突破</span></span>
<span class="line"><span>二次回踩：提高结构质量</span></span>
<span class="line"><span>远离③追价：盈亏比恶化</span></span></code></pre></div><p>最重要的一句话：</p><blockquote><p>先保证结构和风险可定义，再考虑成交价格；错过一笔交易，比在目标空间不足时追价更安全。</p></blockquote><blockquote><p>本章用于交易教育和个人研究，不构成投资建议。图例为构造示例，不能直接视为实时买卖信号。</p></blockquote>`,50)])])}const g=s(l,[["render",i]]);export{b as __pageData,g as default};
